#include<bits/stdc++.h>
#define ll long long
#define endl '\n'
using namespace std;
int n;
int main()
{
    cin>>n;
    int a[n+1];
    for(int i=1;i<=n;i++)
    cin>>a[i];
    int ans=-1000000000;
    for(int i=1;i<=n;i++)
    {
        ans=max(ans,a[i]);
        if(i>1)
        ans=max(ans,a[i]+a[i-1]);
        if(i<n)
        ans=max(ans,a[i]+a[i+1]);
        if(i>1&&i<n)
        ans=max(ans,a[i]+a[i+1]+a[i-1]);
    }
    cout<<ans<<endl;
}
